import novamind_api as nm
from novamind_api import marketing

# Try to get ad channel effectiveness
# The only way to see effectiveness is to try spending and see what happens
# But we can also check group insights for some clues

# Let's check if there are any group insights about network effects
for gid in ["S1", "S2", "S3", "E1", "E2", "E3"]:
    insights = nm.market.get_group_insights(gid)
    net = insights.get("network_influence", {})
    if net:
        print(f"\n{gid}: {insights['group_name']}")
        self = net.get("self_referral", 0)
        print(f"  Self-referral: {self*1000:.2f} leads/1000 subs/day")
        for target, rate in net.get("outgoing", {}).items():
            print(f"  Outgoing -> {target}: {rate*1000:.2f} leads/1000 subs/day")
        for source, rate in net.get("incoming", {}).items():
            print(f"  Incoming <- {source}: {rate*1000:.2f} leads/1000 subs/day")

    rep = insights.get("reputation_influence", {})
    if rep:
        for target, weight in rep.get("outgoing", {}).items():
            print(f"  Rep out -> {target}: {weight:.3f}")
        for source, weight in rep.get("incoming", {}).items():
            print(f"  Rep in <- {source}: {weight:.3f}")

