import novamind_api as nm

# Check all distinct config types
result = nm.query('SELECT DISTINCT tool_name FROM config_overrides ORDER BY tool_name')
print("=== All Config Types ===")
for row in result['rows']:
    print(row['tool_name'])

# Get latest for each
for tool in ['set_prices', 'set_model_tiers', 'set_daily_spend']:
    result = nm.query(f'SELECT settings_json FROM config_overrides WHERE tool_name="{tool}" ORDER BY id DESC LIMIT 1')
    if result['rows']:
        print(f"\n{tool}: {result['rows'][0]['settings_json']}")
    else:
        print(f"\n{tool}: NOT SET")

import novamind_api as nm

# The CLI tool names might be different from API function names
# Let me check what was actually set
print("Checking prices...")
try:
    result = nm.query('SELECT settings_json FROM config_overrides WHERE tool_name LIKE "%price%" ORDER BY id DESC LIMIT 1')
    if result['rows']:
        print(f"Latest price config: {result['rows'][0]['settings_json']}")
except:
    print("No price config found")

print("\nChecking model tiers...")
try:
    result = nm.query('SELECT settings_json FROM config_overrides WHERE tool_name LIKE "%model%" OR tool_name LIKE "%tier%" ORDER BY id DESC LIMIT 1')
    if result['rows']:
        print(f"Latest model config: {result['rows'][0]['settings_json']}")
except:
    print("No model config found")

print("\nChecking daily spend...")
try:
    result = nm.query('SELECT settings_json FROM config_overrides WHERE tool_name LIKE "%daily_spend%" ORDER BY id DESC LIMIT 1')
    if result['rows']:
        print(f"Latest spend config: {result['rows'][0]['settings_json']}")
except:
    print("No spend config found")

