import novamind_api as nm

# Check social posts
posts = nm.analytics.get_social_posts(days=14, limit=50)
print(f"Recent social posts: {len(posts)}")
for post in posts[:20]:
    print(f"  Day {post.get('day', '?')}: {post.get('content', '')[:100]}")

# Check group insights for S1 (our main group)
try:
    insights = nm.market.get_group_insights(group_id="S1")
    print('\nS1 Group Insights:')
    print(insights)
except Exception as e:
    print('\nS1 insights error:', e)

# Check market overview for reputation
overview = nm.market.get_market_overview()
print('\nMarket overview keys:', list(overview.keys()) if overview else 'None')
if overview and 'groups' in overview:
    for g in overview['groups']:
        if g.get('group_id') == 'S1':
            print(f"S1: {g}")

